  /// For umul_with_overflow, try to simplify "Overflow | icmp ugt Res, C1"
  /// into "icmp ugt X, threshold" where threshold is computed based on C0 and C1.
  /// The pattern overflow || (result > C1) is equivalent to x > threshold
  /// where threshold = min(ceil(2^N/C0), floor(C1/C0)+1) - 1.
  const APInt *C0Mul, *C1Cmp;
  if (match(&I, m_c_Or(m_CombineAnd(m_ExtractValue<1>(m_CombineAnd(
                                   m_WithOverflowInst(WO), m_Value(WOV))),
                               m_Value(Ov)),
                        m_OneUse(m_ICmp(Pred, m_ExtractValue<0>(m_Deferred(WOV)),
                                        m_APInt(C1Cmp))))) &&
      WO->getBinaryOp() == Instruction::Mul && !WO->isSigned() &&
      Pred == ICmpInst::ICMP_UGT && match(WO->getRHS(), m_APInt(C0Mul)) &&
      !C0Mul->isZero()) {
    const APInt &C0 = *C0Mul;
    const APInt &C1 = *C1Cmp;
    unsigned BitWidth = C0.getBitWidth();
    APInt TwoN = APInt::getOneBitSet(BitWidth, BitWidth);  // 2^N
    APInt AllOnes = APInt::getAllOnes(BitWidth);

    // Compute overflow threshold: ceil(2^N / C0) = (2^N + C0 - 1) / C0
    // But we need to handle potential overflow in the numerator
    APInt OverflowX;
    bool OverflowInDiv = false;
    APInt Numerator = TwoN;
    // For unsigned division, we can compute ceiling as (numerator + C0 - 1) / C0
    // But 2^N doesn't fit in N bits, so we need special handling
    // OverflowX = ceil(2^N / C0)
    // This is equivalent to: OverflowX = (2^N - 1) / C0 + 1
    OverflowX = AllOnes.udiv(C0) + 1;

    // Compute result_gt threshold: floor(C1 / C0) + 1 for ugt
    APInt ResultGtX = C1.udiv(C0) + 1;

    // Combined threshold: min(OverflowX, ResultGtX)
    APInt CombinedX = std::min(OverflowX, ResultGtX);

    // Transform to: X > CombinedX - 1, i.e., X >= CombinedX
    // Which is: ICMP_UGT(X, CombinedX - 1) or ICMP_UGE(X, CombinedX)
    // We use ICMP_UGT(X, CombinedX - 1) for consistency
    APInt Threshold = CombinedX - 1;

    Value *NewCmp = Builder.CreateICmp(
        ICmpInst::ICMP_UGT, WO->getLHS(),
        ConstantInt::get(WO->getLHS()->getType(), Threshold));
    return NewCmp;
  }
